import React, { useState } from "react";
import {
  Box, Button, Container, TextField, Typography, Paper, Alert, CircularProgress
} from "@mui/material";
import { useNavigate } from "react-router-dom";
import axios from "axios";

export default function Login() {
  const navigate = useNavigate();
  const [mobile, setMobile] = useState("");
  const [otp, setOtp] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [otpSent, setOtpSent] = useState(false);

  // 1️⃣ Request OTP
  const requestOtp = async () => {
    if (!/^[6-9]\d{9}$/.test(mobile)) {
      setError("Enter a valid 10-digit mobile number starting with 6-9");
      return;
    }

    setLoading(true);
    setError("");
    try {
      // Call signup API with mobile only to generate OTP (for testing)
      const res = await axios.post("http://localhost:5000/api/auth/signup", { mobile });
      if (res.data.success) {
        setOtpSent(true);
        setSuccess("OTP sent! Use '123456' for testing");
      } else {
        setError(res.data.message || "Failed to send OTP");
      }
    } catch (err) {
      setError(err.response?.data?.message || "Server error");
    } finally {
      setLoading(false);
    }
  };

  // 2️⃣ Verify OTP and login
  const handleLogin = async (e) => {
    e.preventDefault();
    if (!mobile || !otp) {
      setError("Mobile and OTP are required");
      return;
    }

    setLoading(true);
    setError("");
    try {
      const res = await axios.post("http://localhost:5000/api/auth/login", { mobile, otp });
      if (res.data.success) {
        setSuccess("Login successful!");
        localStorage.setItem("token", res.data.token); // save JWT
        setTimeout(() => navigate("/dashboard"), 700);
      } else {
        setError(res.data.message || "Login failed");
      }
    } catch (err) {
      setError(err.response?.data?.message || "Server error");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Container maxWidth="sm">
      <Paper elevation={3} sx={{ p: 4, mt: 5, borderRadius: 3 }}>
        <Typography variant="h4" align="center" gutterBottom sx={{ color: "orangered" }}>
          Rider App Login
        </Typography>

        {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}
        {success && <Alert severity="success" sx={{ mb: 2 }}>{success}</Alert>}

        <Box component="form" onSubmit={handleLogin}>
          <TextField
            fullWidth
            label="Mobile Number"
            value={mobile}
            onChange={(e) => setMobile(e.target.value)}
            margin="normal"
            inputProps={{ maxLength: 10 }}
            required
          />

          {otpSent && (
            <TextField
              fullWidth
              label="OTP"
              value={otp}
              onChange={(e) => setOtp(e.target.value)}
              margin="normal"
              required
            />
          )}

          {!otpSent ? (
            <Button
              fullWidth
              variant="contained"
              sx={{ mt: 2, bgcolor: "orangered", "&:hover": { bgcolor: "darkred" } }}
              onClick={requestOtp}
              disabled={loading}
            >
              {loading ? <CircularProgress size={24} sx={{ color: "white" }} /> : "Request OTP"}
            </Button>
          ) : (
            <Button
              type="submit"
              fullWidth
              variant="contained"
              sx={{ mt: 2, bgcolor: "orangered", "&:hover": { bgcolor: "darkred" } }}
              disabled={loading}
            >
              {loading ? <CircularProgress size={24} sx={{ color: "white" }} /> : "Login"}
            </Button>
          )}
        </Box>

        <Typography align="center" sx={{ mt: 2 }}>
          Don't have an account? <Button variant="text" onClick={() => navigate("/register")} sx={{ color: "orangered" }}>Register</Button>
        </Typography>
      </Paper>
    </Container>
  );
}
